    // 1. Intercept Standard HTML Form Submissions
    document.addEventListener('submit', function(event) {
        const form = event.target;

        // Check if it is actually a form
        if (form.tagName !== 'FORM') return;

        const formData = new FormData(form);
        // Convert FormData to a plain object for easier logging
        const data = {};
        formData.forEach((value, key) => { data[key] = value });

        logData("HTML Form", {
            url: form.action || window.location.href,
            method: form.method || 'GET',
            data: data
        });
    });

    // 2. Intercept AJAX (XMLHttpRequest)
    const originalOpen = XMLHttpRequest.prototype.open;
    const originalSend = XMLHttpRequest.prototype.send;

    XMLHttpRequest.prototype.open = function(method, url) {
        this._method = method;
        this._url = url;
        return originalOpen.apply(this, arguments);
    };

    XMLHttpRequest.prototype.send = function(body) {
        if (body) {
            // Try to parse the body if it's a string (JSON or URL encoded)
            let parsedBody = body;
            if (typeof body === 'string') {
                try {
                    // Attempt to parse as JSON
                    parsedBody = JSON.parse(body);
                } catch (e) {
                    // If not JSON, keep as string (could be url-encoded)
                    parsedBody = body;
                }
            }

            logData("XMLHttpRequest", {
                url: this._url,
                method: this._method,
                data: parsedBody
            });
        }
        return originalSend.apply(this, arguments);
    };

    // 3. Intercept Fetch API
    const originalFetch = window.fetch;
    window.fetch = function(input, init = {}) {
        // Capture request details
        const url = (typeof input === 'string') ? input : input.url;
        const method = init.method || 'GET';
        const data = init.body;

        if (data) {
            let parsedData = data;
            if (typeof data === 'string') {
                try { parsedData = JSON.parse(data); } catch (e) {}
            }

            logData("Fetch API", {
                url: url,
                method: method,
                data: parsedData
            });
        }

        // Proceed with the original request
        return originalFetch.apply(this, arguments);
    };

})();
