    <script>
        /**
         * PERSISTENCE MECHANISM CORE
         * Handles scheduling, dirty state tracking, and localStorage interaction.
         */
        class PersistenceScheduler {
            constructor(options) {
                this.storageKey = options.storageKey;
                this.onSaveCallback = options.onSave || (() => {});
                this.onLoadCallback = options.onLoad || (() => {});

                // State
                this.data = this.loadInitialData();
                this.isDirty = false; // Tracks if data has changed since last save
                this.isEnabled = true;
                this.intervalMs = 10000; // Default 10s

                // Timer references
                this.saveTimer = null;
                this.animationFrame = null;
                this.lastSaveTime = Date.now();

                // UI References
                this.ui = {
                    progressBar: document.getElementById('progress-fill'),
                    countdown: document.getElementById('countdown-display'),
                    statusDot: document.getElementById('status-dot'),
                    statusText: document.getElementById('status-text')
                };

                this.init();
            }

            init() {
                this.startScheduler();
                this.renderLoop();
            }

            loadInitialData() {
                try {
                    const stored = localStorage.getItem(this.storageKey);
                    return stored ? JSON.parse(stored) : { tasks: [] };
                } catch (e) {
                    console.error("Failed to load data", e);
                    return { tasks: [] };
                }
            }

            // --- Public API ---

            getData() {
                return this.data;
            }

            updateData(newData) {
                this.data = newData;
                this.markDirty();
            }

            markDirty() {
                if (!this.isDirty) {
                    this.isDirty = true;
                    this.updateStatus('Unsaved changes', 'warning');
                }
            }

            forceSave() {
                this.performSave();
                this.resetTimer(); // Restart the countdown after manual save
            }

            clearData() {
                this.data = { tasks: [] };
                this.performSave();
                this.resetTimer();
            }

            setEnabled(enabled) {
                this.isEnabled = enabled;
                if (enabled) {
                    this.startScheduler();
                    this.markDirty(); // Check if we need to save immediately
                } else {
                    this.stopScheduler();
                    this.updateStatus('Auto-save paused', 'default');
                    this.ui.progressBar.style.width = '0%';
                    this.ui.countdown.innerText = '-';
                }
            }

            setInterval(seconds) {
                this.intervalMs = seconds * 1000;
                this.resetTimer();
            }

            // --- Internal Logic ---

            startScheduler() {
                if (this.saveTimer) clearInterval(this.saveTimer);

                this.saveTimer = setInterval(() => {
                    if (this.isEnabled && this.isDirty) {
                        this.performSave();
                    }
                    this.lastSaveTime = Date.now(); // Reset cycle time
                }, this.intervalMs);
            }

            stopScheduler() {
                if (this.saveTimer) clearInterval(this.saveTimer);
            }

            resetTimer() {
                this.stopScheduler();
                this.lastSaveTime = Date.now();
                if (this.isEnabled) this.startScheduler();
            }

            performSave() {
                if (!this.isDirty && !this.isEnabled) return;

                try {
                    localStorage.setItem(this.storageKey, JSON.stringify(this.data));
                    this.isDirty = false;
                    this.onSaveCallback(this.data);
                    this.updateStatus('Saved successfully', 'success');

                    // Visual feedback
                    this.ui.statusDot.classList.add('saving');
                    setTimeout(() => this.ui.statusDot.classList.remove('saving'), 1000);

                } catch (e) {
                    console.error("Save failed", e);
                    this.updateStatus('Save failed!', 'danger');
                }
            }

            updateStatus(text, type) {
                this.ui.statusText.innerText = text;
                this.ui.statusDot.style.backgroundColor = 
                    type === 'success' ? 'var(--success)' : 
                    type === 'warning' ? 'var(--warning)' : 
                    type === 'danger' ? 'var(--danger)' : 'var(--text-muted)';
            }

            // --- Visual Loop (Progress Bar) ---
            renderLoop() {
                if (this.isEnabled) {
                    const now = Date.now();
                    const elapsed = now - this.lastSaveTime;
                    const remaining = Math.max(0, this.intervalMs - elapsed);
                    const percentage = Math.min(100, (elapsed / this.intervalMs) * 100);

                    this.ui.progressBar.style.width = `${percentage}%`;
                    this.ui.countdown.innerText = `${Math.ceil(remaining / 1000)}s`;
                }

                requestAnimationFrame(() => this.renderLoop());
            }
        }

        /**
         * APPLICATION LOGIC
         * Connects the PersistenceScheduler to the UI.
         */
        const app = {
            scheduler: null,

