                currentData.tasks = currentData.tasks.filter(t => t.id !== id);
                this.scheduler.updateData(currentData);
                this.renderTasks(currentData.tasks);
            },

            onDataSaved(data) {
                // Optional: Trigger specific UI updates on save
                // For now, the toast is handled by the scheduler or manual button
            },

            renderTasks(tasks) {
                const list = document.getElementById('task-list');
                list.innerHTML = '';

                if (tasks.length === 0) {
                    list.innerHTML = `
                        <li class="empty-state">
                            <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="#d1d5db" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" style="margin-bottom: 1rem;">
                                <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path>
                                <polyline points="14 2 14 8 20 8"></polyline>
                                <line x1="16" y1="13" x2="8" y2="13"></line>
                                <line x1="16" y1="17" x2="8" y2="17"></line>
                                <polyline points="10 9 9 9 8 9"></polyline>
                            </svg>
                            <p>No tasks yet. Add one above!</p>
                        </li>
                    `;
                    return;
                }

                tasks.forEach(task => {
                    const li = document.createElement('li');
                    li.className = `task-item ${task.completed ? 'completed' : ''}`;
                    li.innerHTML = `
                        <input type="checkbox" class="task-checkbox" ${task.completed ? 'checked' : ''}>
                        <span class="task-text">${this.escapeHtml(task.text)}</span>
                        <button class="task-delete" aria-label="Delete task">
                            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
                        </button>
                    `;

                    // Bind events for this item
                    const checkbox = li.querySelector('.task-checkbox');
                    checkbox.addEventListener('change', () => this.toggleTask(task.id));

                    const delBtn = li.querySelector('.task-delete');
                    delBtn.addEventListener('click', () => this.deleteTask(task.id));

                    list.appendChild(li);
                });
            },

            escapeHtml(text) {
                const div = document.createElement('div');
                div.textContent = text;
                return div.innerHTML;
            }
        };

        /**
         * TOAST NOTIFICATION SYSTEM
         */
        function showToast(message, type = 'info') {
            const container = document.getElementById('toast-container');
            const toast = document.createElement('div');
            toast.className = `toast ${type}`;

